#include <bits/stdc++.h>
using namespace std;

const int N=110;

int n,m,f[N][N];

int main(){
    memset(f,0x3f,sizeof(f));
    scanf("%d%d",&n,&m);
    for(int i=0,u,v;i<m;i++){
        scanf("%d%d",&u,&v);
        f[u][v]=f[v][u]=1;
    }
    for(int i=1;i<=n;i++)
        f[i][i]=0;
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
    int ans=0;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            ans=max(ans,f[i][j]);
    printf("%d",ans);
    return 0;
}
